\documentclass[12pt,a4paper]{article}
\usepackage[margin=1in]{geometry}
\usepackage{amsmath}
\usepackage{amssymb}
\usepackage{amsthm}
\usepackage{tcolorbox}

\title{\textbf{Ordinary Differential Equations (ODEs) - Explained}}
\author{Devulapalli Abhiram}
\date{\today}

\begin{document}

\maketitle

\section{Introduction}
An \textbf{Ordinary Differential Equation (ODE)} is an equation involving a function of one independent variable and its derivatives.

\section{Order and Degree}
\begin{itemize}
\item \textbf{Order}: Highest derivative present in the equation.
\item \textbf{Degree}: Power of the highest order derivative.
\end{itemize}

\section{First Order ODEs}

\begin{tcolorbox}[title=Separable Equations]
\[
\frac{dy}{dx} = f(x) \cdot g(y)
\]
\end{tcolorbox}

\begin{tcolorbox}[title=Linear First Order]
\[
\frac{dy}{dx} + P(x)y = Q(x)
\]
Integrating Factor = $e^{\int P(x)\, dx}$
\end{tcolorbox}

\section{Applications}
\begin{itemize}
\item Population growth models
\item Radioactive decay
\item Simple harmonic motion
\item Electrical circuits
\item Heat transfer
\end{itemize}

\end{document}

